export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "星期二傍晚。她沒有睡很久。琴音走了之後她躺了兩個小時，醒來的時候窗外已經開始暗。她做的第一件事是打開手機，搜「有明車輛基地」。", background: Background.Chapter_4_Ch4_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "灣岸新交通的官方網站有一頁車輛基地介紹。有明基地。位於灣岸線南端。負責車輛維護、夜間停泊、事故車輛暫存。頁面很乾淨，幾張空拍照片，一段制式文字。沒有提到任何事故。沒有提到第七車。沒有提到她。", background: Background.Chapter_4_Ch4_Act4_S0 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）車在那裡。站務主管說的。明天上午移過去。", background: Background.Chapter_4_Ch4_Act4_S0, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她翻到客服頁面。有一支電話。有一個線上諮詢表單。她盯著表單看了很久。表單要填姓名、聯絡方式、諮詢事項。她知道如果填下去，她的名字就會進入一條紀錄。一條「朝倉澪曾經查詢事故車資料」的紀錄。", background: Background.Chapter_4_Ch4_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她還是打了電話。", background: Background.Chapter_4_Ch4_Act4_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "轉了兩次。等待音是灣岸新交通的企業旋律，電子琴編曲，循環播放。她聽了四分鐘。然後有人接了。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.CustomerService, character: "客服", dialogue: "您好，這裡是灣岸新交通客服中心。請問有什麼可以幫您的嗎？", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我想問一下灣岸新交通第七車的事故。那輛車是不是在有明車輛基地？", background: Background.Chapter_4_Ch4_Act4_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.CustomerService, character: "客服", dialogue: "請問您是事故當事人還是家屬？", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我在那輛車上。", background: Background.Chapter_4_Ch4_Act4_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.CustomerService, character: "客服", dialogue: "了解。事故相關資料的調閱，需要透過警方、律師或正式司法程序提出申請。一般乘客無法直接申請車輛相關資料。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我不是要申請資料。我只是想確認車還在那裡。車上的紀錄——原始檔案——還在嗎？", background: Background.Chapter_4_Ch4_Act4_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "電話那頭停了一秒。不是遲疑。是切換。像客服人員在螢幕上點開了另一個頁面。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.CustomerService, character: "客服", dialogue: "這個案子已經轉入安全資料保存流程了。資料的保存和調閱都要按照規定辦理。如果您需要進一步了解，建議您透過警方或律師提出正式申請。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "安全資料保存流程是什麼？", background: Background.Chapter_4_Ch4_Act4_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.CustomerService, character: "客服", dialogue: "流程都要按照規定走。我這邊沒辦法提供更多說明。建議您聯繫警方或律師。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "同一段話。換了幾個字的順序。像一扇門在她面前關上，然後又關上一次。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "那技術班——是不是技術班負責提取原始檔？", background: Background.Chapter_4_Ch4_Act4_S1, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.CustomerService, character: "客服", dialogue: "車輛相關資料的處理均依規定辦理。我這邊無法確認具體作業內容。建議您透過正式程序提出申請。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她掛了電話。螢幕上的通話時間是六分四十二秒。她得到的東西是：事故車在有明基地。資料已轉入公共安全資料保全流程。她不能調閱。技術班會處理。但客服不能確認。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）原始檔存在。它在安全資料單元裡。技術班會抽取。但抽取之後會去哪裡，沒有人會告訴我。", background: Background.Chapter_4_Ch4_Act4_S1, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看了一眼窗外。天已經完全暗了。她把琴音帶來的深色外套穿上，把斜背包掛上肩。手機在外側口袋。小鏡子留在書桌上——她不帶它出門。悠真的東西不能跟著她進入任何一個流程。她出門了。", background: Background.Chapter_4_Ch4_Act4_S1 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "有明車輛基地在灣岸線南端。她從最近的車站走過去，沿著一條沒有路燈的步道。步道一邊是水，一邊是鐵絲網。鐵絲網很高，上面掛著遮蔽網，看不穿。但她沿著網走，走到一段遮蔽網比較稀疏的地方，停下來。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她透過網的縫隙往裡看。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "基地裡面很大。幾條軌道並排，上面停著列車。大部分是正常的灣岸新交通車廂，燈滅著，像睡著了。但在最裡面、最遠的那條軌道上，有一節車廂被隔開了。旁邊沒有其他車。周圍拉著黃色的警示帶。車門上貼著什麼東西——她看不太清楚，但那個形狀和顏色是封存條。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）第七車。在那裡。", background: Background.Chapter_4_Ch4_Act4_S2, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機拿出來。打開相機。她把鏡頭湊到鐵絲網的縫隙上，對準那節被封存的車廂。螢幕裡的畫面很暗。她放大。封存條上的字太小，解析度不夠。她放大到最大。字糊了。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機舉高，換了一個角度。螢幕裡出現了車廂側面的一個東西——不是封存條。是一個貼在車體上的標籤。維修標籤。她放大。標籤是白色的，上面有印刷字。她看見了幾個字元。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）7-CAM。下面還有一行。T開頭的什麼。CAM。看不清楚。", background: Background.Chapter_4_Ch4_Act4_S2, portrait: Portrait.AsakuraMio_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "7-CAM。T什麼CAM。她看見了。但她不確定。距離太遠。光線太暗。她放大到極限，字元的邊緣已經散成像素。7 後面是什麼。CAM 前面的 T 後面是什麼。她不知道。她只看見了碎片。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她想拍下來。她的手指已經按在快門鍵上了。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.SecurityGuard, character: "保全", dialogue: "喂，那邊那位。你在做什麼？", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "聲音從右邊來。她轉頭。一個穿制服的人從步道那頭走過來。手電筒的光打在她臉上。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.SecurityGuard, character: "保全", dialogue: "這裡不能進。請離開。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "我只是在路邊走——", background: Background.Chapter_4_Ch4_Act4_S2, portrait: Portrait.AsakuraMio_Scared },
    { characterId: CharacterId.SecurityGuard, character: "保全", dialogue: "拿手機拍裡面不算路過。請把手機收起來，離開。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她的手指從快門鍵上移開了。她沒有按下。她不知道自己為什麼沒有按。也許是因為那個人的語氣。也許是因為她突然意識到——如果她拍了，這張照片就會存在她的手機裡。她的手機被備份過。如果有人查她的手機，他們會看見她在有明車輛基地外圍拍了一張事故車的照片。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "⋯⋯好。我知道了。", background: Background.Chapter_4_Ch4_Act4_S2, portrait: Portrait.AsakuraMio_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機收進口袋。她轉身。她沿著步道往回走。手電筒的光在她背後跟了幾秒，然後滅了。腳步聲沒有跟過來。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她走了大概兩百公尺才停下來。她站在一個沒有路燈的路口。風從水面吹過來。她把手機拿出來，打開備忘錄。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）7-CAM。T什麼CAM。封存條。隔離軌道。安全資料保存流程。技術班。", background: Background.Chapter_4_Ch4_Act4_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把這幾個詞打進備忘錄。一個一個。像在填查核表。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）原始檔存在。但它正在離我越來越遠。", background: Background.Chapter_4_Ch4_Act4_S2, portrait: Portrait.AsakuraMio_Exhausted },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她看著備忘錄裡的那幾行字。然後她抬頭看了一眼基地的方向。鐵絲網在暗處。裡面的燈還亮著。那節被封存的車廂還在那裡。車載原始檔還在車裡。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但「安全資料保存流程」這幾個字，像一條正在收攏的繩子。事故車被封存了。資料被轉入了。技術班會抽取。抽取之後會進入流程。流程會把它送到她到不了的地方。下週一之前。也許更早。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她站在路口。風把她的頭髮吹到臉上。她沒有撥開。她在想一件事。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.AsakuraMio, character: "朝倉澪", dialogue: "（內心）如果原始檔記得中央流忘記的事。如果它拍到了千田把外殼塞給我。那它就是唯一能證明我版本的東西。而它正在被送進一個我碰不到的流程裡。", background: Background.Chapter_4_Ch4_Act4_S2, portrait: Portrait.AsakuraMio_Determined },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她把手機螢幕按滅。她繼續走。步道很長。兩邊是水和暗。她的腳步聲在地面上一一下一下，很規律。", background: Background.Chapter_4_Ch4_Act4_S2 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "她沒有回頭。", background: Background.Chapter_4_Ch4_Act4_S2 },
];
